1	interface Item {
2	  type: string;
3	  material: string;
4	  enchantment: number;
5	  cursed: boolean;
6	}
7	
8	interface Step {
9	  op: "quote";
10	  items: Item[];
11	}
12	
13	interface Scenario {
14	  customer: { yearsWithMHPCO: number };
15	  steps: Step[];
16	}
17	
18	interface StepResult {
19	  premium: number;
20	}
21	
22	interface ScenarioResult {
23	  results: StepResult[];
24	}
25	
26	const BASE_PREMIUMS: Record<string, number> = {
27	  sword: 100,
28	  amulet: 60,
29	  staff: 80,
30	  potion: 40,
31	  rune: 25,
32	  moonstone: 25,
33	};
34	
35	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
36	const PROCESSING_FEE = 5;
37	const BLOCK_SIZE = 3;
38	const BLOCK_PRICE = 60;
39	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
40	
41	const calculateQuotePremium = (items: Item[]): number => {
42	  let basePremium = 0;
43	  let itemSurcharges = 0;
44	  const componentCounts: Record<string, number> = {};
45	
46	  for (const item of items) {
47	    if (COMPONENT_TYPES.has(item.type)) {
48	      componentCounts[item.type] = (componentCounts[item.type] || 0) + 1;
49	    } else {
50	      const itemBase = BASE_PREMIUMS[item.type];
51	      basePremium += itemBase;
52	      if (item.cursed) {
53	        itemSurcharges += itemBase * 0.5;
54	      }
55	    }
56	  }
57	
58	  for (const [type, count] of Object.entries(componentCounts)) {
59	    basePremium += count === BLOCK_SIZE ? BLOCK_PRICE : count * BASE_PREMIUMS[type];
60	  }
61	
62	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_SURCHARGE_RATE;
63	  return Math.ceil(basePremium + itemSurcharges + firstInsuranceSurcharge) + PROCESSING_FEE;
64	};
65	
66	export const processScenario = (scenario: Scenario): ScenarioResult => {
67	  const results = scenario.steps.map((step) => ({
68	    premium: calculateQuotePremium(step.items),
69	  }));
70	  return { results };
71	};
